sys_script_include.script:
var MoneyIncreaseHelper = Class.create();
MoneyIncreaseHelper.prototype = {
    initialize: function() {},

    /**
     * Returns the approver group/role name based on the requested cap amount.
     * $200 -> GVP
     * $300 -> SVP
     * $500 -> VP
     * @param {string|number} capAmount - The requested cap amount
     * @returns {string} - Role label for routing
     */
    getApproverRole: function(capAmount) {
        var amount = parseInt(capAmount, 10);
        if (amount === 200) return 'GVP';
        if (amount === 300) return 'SVP';
        if (amount === 500) return 'VP';
        return 'UNKNOWN';
    },

    /**
     * Looks up the approver user sys_id based on title matching the role label.
     * Falls back to the RITM's assignment group manager if no exact title match found.
     * @param {string} roleLabel - 'GVP', 'SVP', or 'VP'
     * @returns {string} - sys_id of the approver user, or empty string
     */
    findApproverByTitle: function(roleLabel) {
        var titleMap = {
            'GVP': 'Group Vice President',
            'SVP': 'Senior Vice President',
            'VP':  'Vice President'
        };
        var titleSearch = titleMap[roleLabel] || roleLabel;
        var gr = new GlideRecord('sys_user');
        gr.addQuery('title', 'CONTAINS', titleSearch);
        gr.addActiveQuery();
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            return gr.getUniqueValue();
        }
        return '';
    },

    /**
     * Updates the RITM after approval:
     * - Sets work_notes with approval summary
     * - Sets comments with approver's comments
     * - Updates a custom approval_comments field if it exists
     * - Sets RITM state to Approved (3)
     * @param {string} ritmSysId    - sys_id of the sc_req_item record
     * @param {string} approverSysId - sys_id of the approving user
     * @param {string} approvalComments - Comments entered by the approver
     * @param {string} capAmount     - The approved cap amount
     */
    updateRITMOnApproval: function(ritmSysId, approverSysId, approvalComments, capAmount) {
        if (!ritmSysId) {
            gs.error('MoneyIncreaseHelper.updateRITMOnApproval: ritmSysId is required.');
            return;
        }

        var ritm = new GlideRecord('sc_req_item');
        if (!ritm.get(ritmSysId)) {
            gs.error('MoneyIncreaseHelper.updateRITMOnApproval: RITM not found - ' + ritmSysId);
            return;
        }

        var approverName = '';
        if (approverSysId) {
            var approverGr = new GlideRecord('sys_user');
            if (approverGr.get(approverSysId)) {
                approverName = approverGr.getDisplayValue('name');
            }
        }

        var roleLabel = this.getApproverRole(capAmount);
        var now = new GlideDateTime().getDisplayValue();

        ritm.work_notes =
            '✅ Money Increase Request APPROVED\n' +
            '------------------------------------\n' +
            'Approved Cap Amount : $' + capAmount + '\n' +
            'Approver Role       : ' + roleLabel + '\n' +
            'Approved By         : ' + (approverName || 'N/A') + '\n' +
            'Approval Date/Time  : ' + now + '\n' +
            '------------------------------------\n' +
            'Approver Comments   : ' + (approvalComments || 'No comments provided.');

        ritm.comments =
            'Your Money Increase Request for $' + capAmount + ' has been approved by ' +
            (approverName || roleLabel) + '.\n\n' +
            'Comments from approver: ' + (approvalComments || 'None.');

        ritm.approval = 'approved';
        ritm.state = 3;

        if (ritm.isValidField('u_approval_comments')) {
            ritm.u_approval_comments = approvalComments || '';
        }

        ritm.update();
        gs.info('MoneyIncreaseHelper: RITM ' + ritmSysId + ' updated successfully after ' + roleLabel + ' approval.');
    },

    /**
     * Updates the RITM after rejection:
     * - Sets work_notes with rejection summary
     * - Sets RITM state to Rejected (4)
     * @param {string} ritmSysId         - sys_id of the sc_req_item record
     * @param {string} approverSysId      - sys_id of the rejecting user
     * @param {string} rejectionComments  - Comments entered by the approver
     * @param {string} capAmount          - The requested (rejected) cap amount
     */
    updateRITMOnRejection: function(ritmSysId, approverSysId, rejectionComments, capAmount) {
        if (!ritmSysId) {
            gs.error('MoneyIncreaseHelper.updateRITMOnRejection: ritmSysId is required.');
            return;
        }

        var ritm = new GlideRecord('sc_req_item');
        if (!ritm.get(ritmSysId)) {
            gs.error('MoneyIncreaseHelper.updateRITMOnRejection: RITM not found - ' + ritmSysId);
            return;
        }

        var approverName = '';
        if (approverSysId) {
            var approverGr = new GlideRecord('sys_user');
            if (approverGr.get(approverSysId)) {
                approverName = approverGr.getDisplayValue('name');
            }
        }

        var roleLabel = this.getApproverRole(capAmount);
        var now = new GlideDateTime().getDisplayValue();

        ritm.work_notes =
            '❌ Money Increase Request REJECTED\n' +
            '------------------------------------\n' +
            'Requested Cap Amount : $' + capAmount + '\n' +
            'Rejector Role        : ' + roleLabel + '\n' +
            'Rejected By          : ' + (approverName || 'N/A') + '\n' +
            'Rejection Date/Time  : ' + now + '\n' +
            '------------------------------------\n' +
            'Rejection Comments   : ' + (rejectionComments || 'No comments provided.');

        ritm.comments =
            'Your Money Increase Request for $' + capAmount + ' has been rejected by ' +
            (approverName || roleLabel) + '.\n\n' +
            'Reason: ' + (rejectionComments || 'None.');

        ritm.approval = 'rejected';
        ritm.state = 4;

        if (ritm.isValidField('u_approval_comments')) {
            ritm.u_approval_comments = rejectionComments || '';
        }

        ritm.update();
        gs.info('MoneyIncreaseHelper: RITM ' + ritmSysId + ' updated after ' + roleLabel + ' rejection.');
    },

    type: 'MoneyIncreaseHelper'
};

sys_hub_flow_logic.logic:
{
  "id": "mon0000000000000000000000flw0001",
  "label": "Money Increase Approval Flow",
  "description": "Routes Money Increase Requests to GVP ($200), SVP ($300), or VP ($500) for approval. Updates RITM with approver comments on completion.",
  "trigger": {
    "id": "trigger_0001",
    "type": "service_catalog",
    "label": "Service Catalog - RITM Created",
    "config": {
      "table": "sc_req_item",
      "catalog_item": "mon0000000000000000000000itm0001",
      "condition": "state=1"
    },
    "outputs": {
      "record": { "label": "Requested Item", "type": "GlideRecord<sc_req_item>" }
    }
  },
  "steps": [
    {
      "id": "step_get_vars",
      "label": "Get Catalog Variables from RITM",
      "type": "action",
      "action": "glide_catalog_lookup_variables",
      "inputs": {
        "ritm": "{{trigger.record.sys_id}}"
      },
      "outputs": {
        "requested_cap_amount": { "label": "Requested Cap Amount", "type": "string" },
        "business_justification": { "label": "Business Justification", "type": "string" },
        "application_name": { "label": "Application Name", "type": "string" }
      }
    },
    {
      "id": "step_branch",
      "label": "Route to Appropriate Approver",
      "type": "if",
      "conditions": [
        {
          "id": "branch_200",
          "label": "$200 Cap - Route to GVP",
          "condition": "{{step_get_vars.requested_cap_amount}} == '200'",
          "steps": [
            {
              "id": "step_gvp_approval",
              "label": "GVP Approval - Request $200 Cap",
              "type": "action",
              "action": "glide_approval_request",
              "inputs": {
                "record": "{{trigger.record}}",
                "approval_field": "approval",
                "approvers": [
                  {
                    "type": "title_lookup",
                    "title": "Group Vice President"
                  }
                ],
                "journal_field": "comments",
                "instructions": "Please review this Money Increase Request for $200 cap on application: {{step_get_vars.application_name}}.\n\nBusiness Justification: {{step_get_vars.business_justification}}\n\nYou MUST provide comments before approving or rejecting.",
                "require_comments": true,
                "approve_label": "Approved",
                "reject_label": "Rejected"
              },
              "outputs": {
                "approval_state": { "label": "Approval State", "type": "string" },
                "approver": { "label": "Approver", "type": "reference" },
                "comments": { "label": "Approver Comments", "type": "string" }
              }
            },
            {
              "id": "step_branch_gvp_result",
              "label": "Check GVP Decision",
              "type": "if",
              "conditions": [
                {
                  "id": "branch_gvp_approved",
                  "label": "GVP Approved",
                  "condition": "{{step_gvp_approval.approval_state}} == 'approved'",
                  "steps": [
                    {
                      "id": "step_update_ritm_approval_200",
                      "label": "Update RITM on GVP Approval",
                      "type": "action",
                      "action": "glide_run_script",
                      "inputs": {
                        "script": "(function(){\n  var helper = new MoneyIncreaseHelper();\n  helper.updateRITMOnApproval(\n    '{{trigger.record.sys_id}}',\n    '{{step_gvp_approval.approver.sys_id}}',\n    '{{step_gvp_approval.comments}}',\n    '200'\n  );\n})()"
                      }
                    }
                  ]
                }
              ],
              "else_steps": [
                {
                  "id": "step_update_ritm_rejection_200",
                  "label": "Update RITM on GVP Rejection",
                  "type": "action",
                  "action": "glide_run_script",
                  "inputs": {
                    "script": "(function(){\n  var helper = new MoneyIncreaseHelper();\n  helper.updateRITMOnRejection(\n    '{{trigger.record.sys_id}}',\n    '{{step_gvp_approval.approver.sys_id}}',\n    '{{step_gvp_approval.comments}}',\n    '200'\n  );\n})()"
                  }
                }
              ]
            }
          ]
        },
        {
          "id": "branch_300",
          "label": "$300 Cap - Route to SVP",
          "condition": "{{step_get_vars.requested_cap_amount}} == '300'",
          "steps": [
            {
              "id": "step_svp_approval",
              "label": "SVP Approval - Request $300 Cap",
              "type": "action",
              "action": "glide_approval_request",
              "inputs": {
                "record": "{{trigger.record}}",
                "approval_field": "approval",
                "approvers": [
                  {
                    "type": "title_lookup",
                    "title": "Senior Vice President"
                  }
                ],
                "journal_field": "comments",
                "instructions": "Please review this Money Increase Request for $300 cap on application: {{step_get_vars.application_name}}.\n\nBusiness Justification: {{step_get_vars.business_justification}}\n\nYou MUST provide comments before approving or rejecting.",
                "require_comments": true,
                "approve_label": "Approved",
                "reject_label": "Rejected"
              },
              "outputs": {
                "approval_state": { "label": "Approval State", "type": "string" },
                "approver": { "label": "Approver", "type": "reference" },
                "comments": { "label": "Approver Comments", "type": "string" }
              }
            },
            {
              "id": "step_branch_svp_result",
              "label": "Check SVP Decision",
              "type": "if",
              "conditions": [
                {
                  "id": "branch_svp_approved",
                  "label": "SVP Approved",
                  "condition": "{{step_svp_approval.approval_state}} == 'approved'",
                  "steps": [
                    {
                      "id": "step_update_ritm_approval_300",
                      "label": "Update RITM on SVP Approval",
                      "type": "action",
                      "action": "glide_run_script",
                      "inputs": {
                        "script": "(function(){\n  var helper = new MoneyIncreaseHelper();\n  helper.updateRITMOnApproval(\n    '{{trigger.record.sys_id}}',\n    '{{step_svp_approval.approver.sys_id}}',\n    '{{step_svp_approval.comments}}',\n    '300'\n  );\n})()"
                      }
                    }
                  ]
                }
              ],
              "else_steps": [
                {
                  "id": "step_update_ritm_rejection_300",
                  "label": "Update RITM on SVP Rejection",
                  "type": "action",
                  "action": "glide_run_script",
                  "inputs": {
                    "script": "(function(){\n  var helper = new MoneyIncreaseHelper();\n  helper.updateRITMOnRejection(\n    '{{trigger.record.sys_id}}',\n    '{{step_svp_approval.approver.sys_id}}',\n    '{{step_svp_approval.comments}}',\n    '300'\n  );\n})()"
                  }
                }
              ]
            }
          ]
        },
        {
          "id": "branch_500",
          "label": "$500 Cap - Route to VP",
          "condition": "{{step_get_vars.requested_cap_amount}} == '500'",
          "steps": [
            {
              "id": "step_vp_approval",
              "label": "VP Approval - Request $500 Cap",
              "type": "action",
              "action": "glide_approval_request",
              "inputs": {
                "record": "{{trigger.record}}",
                "approval_field": "approval",
                "approvers": [
                  {
                    "type": "title_lookup",
                    "title": "Vice President"
                  }
                ],
                "journal_field": "comments",
                "instructions": "Please review this Money Increase Request for $500 cap on application: {{step_get_vars.application_name}}.\n\nBusiness Justification: {{step_get_vars.business_justification}}\n\nYou MUST provide comments before approving or rejecting.",
                "require_comments": true,
                "approve_label": "Approved",
                "reject_label": "Rejected"
              },
              "outputs": {
                "approval_state": { "label": "Approval State", "type": "string" },
                "approver": { "label": "Approver", "type": "reference" },
                "comments": { "label": "Approver Comments", "type": "string" }
              }
            },
            {
              "id": "step_branch_vp_result",
              "label": "Check VP Decision",
              "type": "if",
              "conditions": [
                {
                  "id": "branch_vp_approved",
                  "label": "VP Approved",
                  "condition": "{{step_vp_approval.approval_state}} == 'approved'",
                  "steps": [
                    {
                      "id": "step_update_ritm_approval_500",
                      "label": "Update RITM on VP Approval",
                      "type": "action",
                      "action": "glide_run_script",
                      "inputs": {
                        "script": "(function(){\n  var helper = new MoneyIncreaseHelper();\n  helper.updateRITMOnApproval(\n    '{{trigger.record.sys_id}}',\n    '{{step_vp_approval.approver.sys_id}}',\n    '{{step_vp_approval.comments}}',\n    '500'\n  );\n})()"
                      }
                    }
                  ]
                }
              ],
              "else_steps": [
                {
                  "id": "step_update_ritm_rejection_500",
                  "label": "Update RITM on VP Rejection",
                  "type": "action",
                  "action": "glide_run_script",
                  "inputs": {
                    "script": "(function(){\n  var helper = new MoneyIncreaseHelper();\n  helper.updateRITMOnRejection(\n    '{{trigger.record.sys_id}}',\n    '{{step_vp_approval.approver.sys_id}}',\n    '{{step_vp_approval.comments}}',\n    '500'\n  );\n})()"
                  }
                }
              ]
            }
          ]
        }
      ]
    }
  ]
}

sysevent_email_action.message:
Dear ${approver.name},

You have been assigned to review a Money Increase Request that requires your approval.

REQUEST DETAILS
---------------
Requested Item  : ${document.cat_item.name}
Requested By    : ${document.request.requested_for.name}
RITM Number     : ${document.number}
Application     : ${document.variables.application_name}
Requested Cap   : $${document.variables.requested_cap_amount}
Current Cap     : $100 (default)

Business Justification:
${document.variables.business_justification}

APPROVAL INSTRUCTIONS
---------------------
Please review this request and provide your approval decision WITH COMMENTS.
Comments are mandatory for both approval and rejection.

Click here to view the request: ${URI_REF}

Thank you,
ServiceNow Automated Notification
